#include <stdlib.h>
#include <omp.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void lud_omp(float *m, int matrix_dim) {
    int i, j, k, offset, bx, by;
    float sum;

    // Local buffers for block processing
    float *shadow = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
    float *dia = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
    float *peri_row = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
    float *peri_col = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));

    // Main iteration over blocks
    for (offset = 0; offset < matrix_dim - BLOCK_SIZE; offset += BLOCK_SIZE) {

        // === lud_diagonal ===
        // Load diagonal block into shadow
        for (i = 0; i < BLOCK_SIZE; i++) {
            int array_offset = offset * matrix_dim + offset;
            for (j = 0; j < BLOCK_SIZE; j++) {
                shadow[i * BLOCK_SIZE + j] = m[array_offset + j];
            }
            array_offset += matrix_dim;
        }

        // LUD on shadow (diagonal block)
        for (i = 0; i < BLOCK_SIZE - 1; i++) {
            // Update upper part
            for (j = i + 1; j < BLOCK_SIZE; j++) {
                for (k = 0; k < i; k++) {
                    shadow[j * BLOCK_SIZE + i] -= shadow[j * BLOCK_SIZE + k] * shadow[k * BLOCK_SIZE + i];
                }
                shadow[j * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
            }

            // Update lower part
            for (j = i + 1; j < BLOCK_SIZE; j++) {
                for (k = 0; k < i + 1; k++) {
                    shadow[(i + 1) * BLOCK_SIZE + j] -= shadow[(i + 1) * BLOCK_SIZE + k] * shadow[k * BLOCK_SIZE + j];
                }
            }
        }

        // Write back diagonal block (rows 1 to BLOCK_SIZE-1)
        int array_offset = (offset + 1) * matrix_dim + offset;
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                m[array_offset + j] = shadow[i * BLOCK_SIZE + j];
            }
            array_offset += matrix_dim;
        }

        // === lud_perimeter ===
        int num_blocks = (matrix_dim - offset - BLOCK_SIZE) / BLOCK_SIZE;

        // Load diagonal
        for (i = 0; i < BLOCK_SIZE / 2; i++) {
            int array_offset = offset * matrix_dim + offset;
            for (j = 0; j < BLOCK_SIZE; j++) {
                dia[i * BLOCK_SIZE + j] = m[array_offset + j];
            }
            array_offset += matrix_dim;
        }

        for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
            int array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
            for (j = 0; j < BLOCK_SIZE; j++) {
                dia[i * BLOCK_SIZE + j] = m[array_offset + j];
            }
            array_offset += matrix_dim;
        }

        // Process perimeter blocks
        for (bx = 0; bx < num_blocks; bx++) {
            // Load peri_row
            int array_offset = offset * matrix_dim + offset + (bx + 1) * BLOCK_SIZE;
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    peri_row[i * BLOCK_SIZE + j] = m[array_offset + j];
                }
                array_offset += matrix_dim;
            }

            // Load peri_col
            array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    peri_col[i * BLOCK_SIZE + j] = m[array_offset + j];
                }
                array_offset += matrix_dim;
            }

            // Update peri_row
            for (i = 1; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    for (k = 0; k < i; k++) {
                        peri_row[i * BLOCK_SIZE + j] -= dia[i * BLOCK_SIZE + k] * peri_row[k * BLOCK_SIZE + j];
                    }
                }
            }

            // Update peri_col
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    for (k = 0; k < i; k++) {
                        peri_col[i * BLOCK_SIZE + j] -= peri_col[i * BLOCK_SIZE + k] * dia[k * BLOCK_SIZE + j];
                    }
                    peri_col[i * BLOCK_SIZE + j] /= dia[i * BLOCK_SIZE + i];
                }
            }

            // Write back peri_row
            array_offset = (offset + 1) * matrix_dim + offset + (bx + 1) * BLOCK_SIZE;
            for (i = 1; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    m[array_offset + j] = peri_row[i * BLOCK_SIZE + j];
                }
                array_offset += matrix_dim;
            }

            // Write back peri_col
            array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    m[array_offset + j] = peri_col[i * BLOCK_SIZE + j];
                }
                array_offset += matrix_dim;
            }
        }

        // === lud_internal ===
        // Process internal blocks
        for (by = 0; by < num_blocks; by++) {
            for (bx = 0; bx < num_blocks; bx++) {
                // Load peri_row
                int global_col_id = offset + (bx + 1) * BLOCK_SIZE;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    for (j = 0; j < BLOCK_SIZE; j++) {
                        peri_row[i * BLOCK_SIZE + j] = m[(offset + i) * matrix_dim + global_col_id + j];
                    }
                }

                // Load peri_col
                int global_row_id = offset + (by + 1) * BLOCK_SIZE;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    for (j = 0; j < BLOCK_SIZE; j++) {
                        peri_col[i * BLOCK_SIZE + j] = m[(global_row_id + i) * matrix_dim + offset + j];
                    }
                }

                // Update internal block
                for (i = 0; i < BLOCK_SIZE; i++) {
                    for (j = 0; j < BLOCK_SIZE; j++) {
                        sum = 0;
                        for (k = 0; k < BLOCK_SIZE; k++) {
                            sum += peri_col[i * BLOCK_SIZE + k] * peri_row[k * BLOCK_SIZE + j];
                        }
                        m[(global_row_id + i) * matrix_dim + global_col_id + j] -= sum;
                    }
                }
            }
        }
    }

    // Final diagonal block
    offset = matrix_dim - BLOCK_SIZE;

    // Load final diagonal block
    for (i = 0; i < BLOCK_SIZE; i++) {
        int array_offset = offset * matrix_dim + offset;
        for (j = 0; j < BLOCK_SIZE; j++) {
            shadow[i * BLOCK_SIZE + j] = m[array_offset + j];
        }
        array_offset += matrix_dim;
    }

    // LUD on final diagonal block
    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            for (k = 0; k < i; k++) {
                shadow[j * BLOCK_SIZE + i] -= shadow[j * BLOCK_SIZE + k] * shadow[k * BLOCK_SIZE + i];
            }
            shadow[j * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
        }

        for (j = i + 1; j < BLOCK_SIZE; j++) {
            for (k = 0; k < i + 1; k++) {
                shadow[(i + 1) * BLOCK_SIZE + j] -= shadow[(i + 1) * BLOCK_SIZE + k] * shadow[k * BLOCK_SIZE + j];
            }
        }
    }

    // Write back final diagonal block
    int array_offset = (offset + 1) * matrix_dim + offset;
    for (i = 1; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[array_offset + j] = shadow[i * BLOCK_SIZE + j];
        }
        array_offset += matrix_dim;
    }

    // Free local buffers
    free(shadow);
    free(dia);
    free(peri_row);
    free(peri_col);
}
